-- Q1 — grammaire — Intermediaire — qcm — Nature d'une proposition
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-000000000001',
  'Francais', 'grammaire', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Intermediaire', 'qcm',
  'Dans la phrase « Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur », quelle est la nature de la proposition « que j''appelais M. Seurel » ?',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  '[{"id":"a","label":"Proposition subordonnée conjonctive complétive"},{"id":"b","label":"Proposition subordonnée relative explicative"},{"id":"c","label":"Proposition subordonnée circonstancielle de comparaison"},{"id":"d","label":"Proposition indépendante juxtaposée"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  '« Que j''appelais M. Seurel » est une proposition subordonnée relative introduite par le pronom relatif « que ». Elle est explicative (appositive) : elle apporte une information supplémentaire sur l''antécédent « Mon père » sans restreindre son identification. Le pronom « que » a pour antécédent « Mon père » et occupe la fonction de COD du verbe « appelais ». La distinction entre relative déterminative et relative explicative est un savoir grammatical attendu au CRPE.',
  'Confondre la relative avec une complétive. « Que » est ici un pronom relatif (il a un antécédent : « Mon père »), pas une conjonction de subordination.',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q2 — grammaire — Difficile — qcm — Fonction d'un pronom relatif
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-000000000002',
  'Francais', 'grammaire', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Difficile', 'qcm',
  'Dans « une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail », quelle est la fonction du pronom relatif « qui » ?',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  '[{"id":"a","label":"Complément d''objet direct de « ouvrait »"},{"id":"b","label":"Sujet du verbe « ouvrait »"},{"id":"c","label":"Complément circonstanciel de lieu"},{"id":"d","label":"Attribut du sujet"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  'Le pronom relatif « qui » est sujet du verbe « ouvrait » dans la subordonnée relative. Son antécédent est « une cour immense ». « Qui » est toujours sujet du verbe de la relative. L''identification de la fonction des pronoms relatifs est un attendu du CRPE et du cycle 3.',
  'Confondre la fonction du pronom relatif avec celle de son antécédent. « La cour » peut avoir une fonction dans la phrase matrice, mais « qui » est sujet dans sa propre proposition.',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q3 — grammaire — Intermediaire — reponse_courte — Fonction d'un groupe
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-000000000003',
  'Francais', 'grammaire', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Intermediaire', 'reponse_courte',
  'Quelle est la fonction du groupe « de cette demeure » dans « le plan sommaire de cette demeure » ?',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  NULL,
  '{"mode":"text","acceptableAnswers":["complément du nom","complement du nom","CDN","cdn","complément du nom plan","complement du nom plan"]}'::jsonb,
  '« De cette demeure » est un complément du nom. Il complète le nom « plan » en précisant de quoi il est le plan. Introduit par la préposition « de », ce groupe prépositionnel fait partie du groupe nominal et ne peut être déplacé librement. Le complément du nom se distingue du COI (qui complète un verbe) et du CC (qui est mobile et supprimable).',
  'Confondre le complément du nom avec un COI ou un CCL. « De cette demeure » ne complète pas un verbe mais un nom (« plan »).',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q4 — grammaire — Difficile — qcm — Nature d'une complétive
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-000000000004',
  'Francais', 'grammaire', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Difficile', 'qcm',
  'Dans « Je pus remarquer qu''il avait des souliers fins, recouverts de boue », quelle est la nature de la proposition « qu''il avait des souliers fins » ?',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  '[{"id":"a","label":"Proposition subordonnée relative"},{"id":"b","label":"Proposition subordonnée conjonctive complétive"},{"id":"c","label":"Proposition subordonnée circonstancielle de cause"},{"id":"d","label":"Proposition indépendante"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  '« Qu''il avait des souliers fins » est une proposition subordonnée conjonctive complétive, COD du verbe « remarquer » (remarquer quoi ? → qu''il avait des souliers fins). Elle est introduite par la conjonction de subordination « que ». « Que » conjonction n''a pas d''antécédent nominal (à la différence du pronom relatif « que ») et n''a aucune fonction à l''intérieur de la subordonnée.',
  'Confondre complétive et relative. Le « que » conjonction n''a pas d''antécédent et n''a pas de fonction dans la subordonnée ; le « que » pronom relatif reprend un nom et a une fonction (COD).',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q5 — grammaire — Difficile — qcm — Nature de « où » pronom relatif
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-000000000005',
  'Francais', 'grammaire', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Difficile', 'qcm',
  'Dans « le Cours Supérieur, où l''on préparait le brevet simple », quelle est la nature du mot « où » ?',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  '[{"id":"a","label":"Adverbe de lieu"},{"id":"b","label":"Conjonction de subordination"},{"id":"c","label":"Pronom relatif"},{"id":"d","label":"Préposition"}]'::jsonb,
  '{"mode":"single_choice","value":"c"}'::jsonb,
  '« Où » est ici un pronom relatif. Il a pour antécédent « le Cours Supérieur » et introduit la subordonnée relative « où l''on préparait le brevet simple ». Dans cette relative, « où » occupe la fonction de complément circonstanciel de lieu du verbe « préparait ». Il ne faut pas confondre le pronom relatif « où » (qui a un antécédent) avec l''adverbe interrogatif « où » (« Où vas-tu ? ») ou la conjonction de subordination.',
  'Analyser « où » comme un simple adverbe de lieu. Ici, « où » a un antécédent nominal (« le Cours Supérieur ») : c''est donc un pronom relatif, pas un adverbe.',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q6 — analyse_langue — Difficile — qcm — Mode verbal imposé par conjonction
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-000000000006',
  'Francais', 'analyse_langue', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Difficile', 'qcm',
  'Dans « bien que la maison ne nous appartienne plus », quel est le mode du verbe « appartienne » et pourquoi ce mode est-il utilisé ?',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  '[{"id":"a","label":"Indicatif présent, car la proposition est assertive"},{"id":"b","label":"Subjonctif présent, imposé par la locution conjonctive de concession « bien que »"},{"id":"c","label":"Conditionnel présent, car le fait est hypothétique"},{"id":"d","label":"Subjonctif imparfait, pour la concordance des temps"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  'Le verbe « appartienne » est au subjonctif présent. La locution conjonctive de concession « bien que » impose systématiquement le subjonctif. C''est une règle régulière : bien que, quoique, encore que appellent le subjonctif. « Appartienne » (subjonctif) se distingue de « appartient » (indicatif) par la terminaison en -e à la 3e personne.',
  'Confondre avec l''indicatif. L''erreur fréquente à l''oral (« bien que… + indicatif ») n''est pas acceptée à l''écrit normé.',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q7 — grammaire — Intermediaire — reponse_courte — Fonction du pronom « y »
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-000000000007',
  'Francais', 'grammaire', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Intermediaire', 'reponse_courte',
  'Quelle est la fonction grammaticale du pronom « y » dans « y dirigeait à la fois le Cours Supérieur » ?',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  NULL,
  '{"mode":"text","acceptableAnswers":["complément circonstanciel de lieu","CCL","CC de lieu","complement circonstanciel de lieu"]}'::jsonb,
  '« Y » est un pronom adverbial qui reprend « les bâtiments du Cours Supérieur de Sainte-Agathe ». Il fonctionne comme complément circonstanciel de lieu du verbe « dirigeait » (il dirigeait DANS ces bâtiments). C''est un pronom invariable qui évite la répétition du complément de lieu.',
  'Confondre la fonction de « y » avec un COI. Ici, « y » remplace un lieu concret, pas un complément abstrait introduit par « à ».',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q8 — grammaire — Difficile — reponse_courte — RÉÉCRITURE féminin pluriel
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-000000000008',
  'Francais', 'grammaire', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Difficile', 'reponse_courte',
  'RÉÉCRITURE — Réécrivez la phrase suivante en mettant le sujet au féminin pluriel. Effectuez toutes les modifications nécessaires : « Un gamin inconnu sauta du marchepied avec agilité. »',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  NULL,
  '{"mode":"text","acceptableAnswers":["Des gamines inconnues sautèrent du marchepied avec agilité.","Des gamines inconnues sautèrent du marchepied avec agilité"]}'::jsonb,
  'Les modifications sont : « Un » → « Des » (déterminant indéfini pluriel) ; « gamin » → « gamines » (féminin pluriel) ; « inconnu » → « inconnues » (accord en genre et en nombre de l''adjectif) ; « sauta » → « sautèrent » (accord du verbe au passé simple, 3e personne du pluriel). « Du marchepied » et « avec agilité » ne changent pas (compléments indépendants du sujet).',
  'Oublier l''accord de l''adjectif « inconnu » au féminin pluriel, ou ne pas modifier le verbe au pluriel.',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q9 — grammaire — Difficile — reponse_courte — RÉÉCRITURE voix passive
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-000000000009',
  'Francais', 'grammaire', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Difficile', 'reponse_courte',
  'RÉÉCRITURE — Mettez la phrase suivante à la voix passive : « Mon père dirigeait le Cours Supérieur. »',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  NULL,
  '{"mode":"text","acceptableAnswers":["Le Cours Supérieur était dirigé par mon père.","Le Cours Supérieur était dirigé par mon père"]}'::jsonb,
  'À la voix passive : le COD (« le Cours Supérieur ») devient sujet ; le verbe passe à la forme passive (être + participe passé : « était dirigé », l''imparfait est conservé) ; le sujet actif (« Mon père ») devient complément d''agent introduit par « par ». Le participe passé « dirigé » s''accorde avec le nouveau sujet « Le Cours Supérieur » (masculin singulier).',
  'Ne pas conserver le temps du verbe (l''imparfait actif doit rester imparfait au passif). Ou oublier le complément d''agent « par mon père ».',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q10 — grammaire — Difficile — reponse_courte — RÉÉCRITURE transposition temporelle
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-00000000000a',
  'Francais', 'grammaire', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Difficile', 'reponse_courte',
  'RÉÉCRITURE — Transposez au passé composé les verbes au passé simple dans la phrase suivante (conservez l''imparfait des verbes descriptifs) : « Un gamin inconnu sauta du marchepied. Il portait un costume de collégien. »',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  NULL,
  '{"mode":"text","acceptableAnswers":["Un gamin inconnu a sauté du marchepied. Il portait un costume de collégien.","Un gamin inconnu a sauté du marchepied. Il portait un costume de collégien"]}'::jsonb,
  'Seul « sauta » (passé simple, action ponctuelle de premier plan) se transpose au passé composé : « a sauté ». « Portait » (imparfait, description d''arrière-plan) reste à l''imparfait car il décrit un état, pas un événement. Dans le système narratif, le passé composé remplace le passé simple pour les actions ponctuelles, mais l''imparfait conserve sa valeur descriptive.',
  'Transposer aussi « portait » au passé composé (« a porté »). L''imparfait de description ne change pas : il décrit un état concomitant, pas une action ponctuelle.',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q11 — orthographe — Intermediaire — qcm — Accord du participe passé
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-00000000000b',
  'Francais', 'orthographe', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Intermediaire', 'qcm',
  'Dans « Nous avons quitté le pays depuis bientôt quinze ans », pourquoi le participe passé « quitté » ne porte-t-il pas de marque d''accord ?',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  '[{"id":"a","label":"Parce que le sujet « nous » est indéfini"},{"id":"b","label":"Parce que le verbe est conjugué avec « avoir » et le COD « le pays » est placé après le participe"},{"id":"c","label":"Parce que « quitter » est un verbe intransitif"},{"id":"d","label":"Parce que le participe passé des verbes du 1er groupe est invariable"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  'Avec l''auxiliaire « avoir », le participe passé ne s''accorde avec le COD que si celui-ci est placé AVANT le participe. Ici, le COD « le pays » est placé APRÈS « quitté », donc pas d''accord. Comparez : « le pays que nous avons quitté » → même forme car « le pays » est masculin singulier ; « les villes que nous avons quittées » → accord féminin pluriel obligatoire car le COD « que » (= les villes) est antéposé.',
  'Penser que le PP avec « avoir » est toujours invariable. Il s''accorde avec le COD antéposé.',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q12 — conjugaison — Intermediaire — qcm — Valeur de l'imparfait
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-00000000000c',
  'Francais', 'conjugaison', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Intermediaire', 'qcm',
  'Quelle est la valeur de l''imparfait dans « Ma mère faisait la petite classe » ?',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  '[{"id":"a","label":"Imparfait de narration"},{"id":"b","label":"Imparfait d''habitude (itératif)"},{"id":"c","label":"Imparfait de description (arrière-plan)"},{"id":"d","label":"Imparfait d''atténuation"}]'::jsonb,
  '{"mode":"single_choice","value":"c"}'::jsonb,
  'L''imparfait « faisait » exprime un état durable servant à planter le décor du récit. C''est l''imparfait descriptif (arrière-plan), qui s''oppose au passé simple des événements ponctuels (« Il arriva », « sauta »). L''alternance imparfait/passé simple structure le récit : l''imparfait décrit le cadre, le passé simple fait avancer l''action.',
  'Confondre avec l''imparfait d''habitude. L''habitude implique la répétition d''actions, tandis que la description présente un état stable du cadre narratif.',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- ── PARTIE 2 · ANALYSE DU LEXIQUE ──────────────────────────

-- Q13 — lexique — Intermediaire — qcm — Champ lexical dominant
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-00000000000d',
  'Francais', 'lexique', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Intermediaire', 'qcm',
  'Quel champ lexical est dominant dans la longue phrase descriptive « Une longue maison rouge… des champs, des jardins et des prés qui rejoignaient les faubourgs » ?',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  '[{"id":"a","label":"Le temps qui passe"},{"id":"b","label":"L''espace et les lieux"},{"id":"c","label":"Les sentiments"},{"id":"d","label":"La nature sauvage"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  'Le champ lexical dominant est celui de l''espace et des lieux : maison, portes, bourg, cour, préaux, buanderie, village, portail, route, grille, champs, jardins, prés, faubourgs, demeure. Les indications directionnelles renforcent ce champ : « à l''extrémité du bourg », « en avant sur le village », « sur le côté nord », « au sud et par derrière ». La description organise l''espace comme un plan géographique.',
  'Confondre avec le champ lexical de la nature. Si « champs, jardins, prés, vignes vierges » évoquent la nature, le champ lexical dominant est plus large : il englobe les bâtiments, les voies et l''organisation spatiale du lieu.',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q14 — lexique — Intermediaire — reponse_courte — Relever un champ lexical
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-00000000000e',
  'Francais', 'lexique', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Intermediaire', 'reponse_courte',
  'Relevez dans le texte quatre mots appartenant au champ lexical du vêtement.',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  NULL,
  '{"mode":"text","acceptableAnswers":["costume, blouse, pantalons, souliers","costume, blouse, ceinturon, pantalons","blouse, ceinturon, pantalons, jambières","costume, blouse, pantalons, jambières","costume, pantalons, jambières, souliers"]}'::jsonb,
  'Le champ lexical du vêtement est présent dans le portrait du nouveau venu : « costume », « blouse », « ceinturon », « pantalons », « jambières », « souliers ». Ces termes précis et datés (« jambières boutonnées », « blouse noire serrée ») situent le personnage socialement (collégien) et historiquement (fin du XIXe siècle).',
  'Inclure « boue » ou « cuir » qui ne sont pas des vêtements mais des matières ou éléments associés.',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q15 — lexique — Difficile — qcm — Formation d'un mot composé
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-00000000000f',
  'Francais', 'lexique', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Difficile', 'qcm',
  'Le mot « marchepied » est un mot composé. De quels éléments est-il formé ?',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  '[{"id":"a","label":"Deux noms juxtaposés (marche + pied)"},{"id":"b","label":"Un verbe + un nom (marcher → marche + pied)"},{"id":"c","label":"Un adjectif + un nom"},{"id":"d","label":"Un préfixe + un radical"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  '« Marchepied » est un mot composé de type verbe + nom : « marche » (forme du verbe « marcher ») + « pied ». Ce mode de composition est productif en français : un marchepied est littéralement « ce sur quoi le pied marche » pour monter. On retrouve ce schéma dans : tire-bouchon, porte-manteau, couvre-lit, garde-fou. L''analyse morphologique des mots composés est un savoir lexical attendu au CRPE.',
  'Analyser « marche » comme un nom (la marche d''un escalier). Dans « marchepied », « marche » est la forme verbale, comme dans les autres composés V+N (porte-monnaie, garde-robe).',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q16 — lexique — Intermediaire — reponse_courte — Suffixation
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-000000000010',
  'Francais', 'lexique', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Intermediaire', 'reponse_courte',
  'Dans « Un gamin inconnu sauta du marchepied avec agilité », identifiez le suffixe du mot « agilité » et précisez quel changement de classe grammaticale il opère.',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  NULL,
  '{"mode":"text","acceptableAnswers":["-ité transforme l''adjectif agile en nom","-ité, adjectif vers nom","suffixe -ité","le suffixe -ité","-ité"]}'::jsonb,
  'Le suffixe « -ité » transforme l''adjectif « agile » en nom « agilité ». C''est un suffixe nominal qui permet de former des noms abstraits désignant une qualité : agile → agilité, rapide → rapidité, fragile → fragilité, fertile → fertilité. Ce processus de dérivation suffixale est un savoir morphologique fondamental au CRPE.',
  'Ne pas identifier le radical « agile » sous le mot « agilité ». La consonne « l » du radical est conservée mais le « e » final tombe devant le suffixe.',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q17 — lexique — Intermediaire — qcm — Registre de langue
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-000000000011',
  'Francais', 'lexique', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Intermediaire', 'qcm',
  'Le mot « demeure » dans « cette demeure où s''écoulèrent les jours les plus tourmentés » appartient à quel registre de langue par rapport au mot « maison » ?',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  '[{"id":"a","label":"Familier"},{"id":"b","label":"Courant"},{"id":"c","label":"Soutenu"},{"id":"d","label":"Argotique"}]'::jsonb,
  '{"mode":"single_choice","value":"c"}'::jsonb,
  '« Demeure » appartient au registre soutenu. Face au mot courant « maison » (utilisé plus haut dans le même texte), « demeure » confère une dimension solennelle et affective au lieu. Ce choix lexical traduit l''émotion du narrateur : le lieu banal (une maison) est élevé au rang de « demeure » par le souvenir. Comparer les registres de synonymes (baraque / maison / demeure / résidence) est un exercice lexical classique du cycle 3 et du CRPE.',
  'Classer « demeure » en registre courant. « Maison » est courant ; « demeure » est soutenu, avec une connotation de noblesse ou de grandeur.',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q18 — lexique — Difficile — qcm — Degré de l'adjectif
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-000000000012',
  'Francais', 'lexique', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Difficile', 'qcm',
  'Dans « les jours les plus tourmentés et les plus chers de ma vie », quel est le degré de l''adjectif ?',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  '[{"id":"a","label":"Comparatif de supériorité"},{"id":"b","label":"Superlatif relatif de supériorité"},{"id":"c","label":"Superlatif absolu"},{"id":"d","label":"Comparatif d''égalité"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  '« Les plus tourmentés » et « les plus chers » sont au superlatif relatif de supériorité. Le superlatif relatif se forme avec l''article défini + plus/moins + adjectif : il exprime le degré le plus élevé par rapport à un ensemble (« de ma vie »). Le superlatif absolu (très + adj.) n''implique pas de comparaison avec un groupe. Le comparatif met en rapport deux éléments seulement.',
  'Confondre superlatif relatif et superlatif absolu. Le superlatif relatif compare au sein d''un ensemble (« de ma vie ») ; le superlatif absolu (très, extrêmement) ne compare pas.',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q19 — lexique — Difficile — qcm — Préfixation et valeur
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-000000000013',
  'Francais', 'lexique', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Difficile', 'qcm',
  'Dans « Un gamin inconnu sauta du marchepied », le préfixe « in- » dans « inconnu » a une valeur :',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  '[{"id":"a","label":"De répétition (comme dans « insister »)"},{"id":"b","label":"De négation (le contraire de « connu »)"},{"id":"c","label":"D''intensification (très connu)"},{"id":"d","label":"De localisation (à l''intérieur)"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  'Le préfixe « in- » dans « inconnu » a une valeur de négation : inconnu = qui n''est pas connu. C''est le même préfixe négatif que dans : impossible, invisible, inégal, incertain. À ne pas confondre avec le « in- » locatif (intérieur, inclure, infiltrer) ni avec le « in- » de « insister » (du latin in- = vers). La valeur du préfixe dépend de son étymologie et du sens du mot.',
  'Confondre le « in- » négatif avec le « in- » locatif. « Inconnu » = pas connu (négatif) ; « inclure » = mettre dedans (locatif). Le contexte et le sens du mot permettent de trancher.',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q20 — lexique — Difficile — qcm — Dérivation suffixale
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6010000-0000-0000-0000-000000000014',
  'Francais', 'lexique', 'sujet_blanc_crpe_1', 'Sujet blanc n°1 — Le Grand Meaulnes', 'Difficile', 'qcm',
  'Dans « le portail rouillé de la cour », le mot « rouillé » est formé par :',
  'Il arriva chez nous un dimanche de novembre 189… Je continue à dire « chez nous », bien que la maison ne nous appartienne plus. Nous avons quitté le pays depuis bientôt quinze ans et nous n''y reviendrons certainement jamais. Nous habitions les bâtiments du Cours Supérieur de Sainte-Agathe. Mon père, que j''appelais M. Seurel, comme les autres élèves, y dirigeait à la fois le Cours Supérieur, où l''on préparait le brevet simple, et le Cours Moyen. Ma mère faisait la petite classe. Une longue maison rouge, avec cinq portes vitrées, sous des vignes vierges, à l''extrémité du bourg ; une cour immense avec préaux et buanderie, qui ouvrait en avant sur le village par un grand portail ; sur le côté nord, la route où donnait une petite grille et qui menait vers La Gare, à trois kilomètres ; au sud et par derrière, des champs, des jardins et des prés qui rejoignaient les faubourgs… tel est le plan sommaire de cette demeure où s''écoulèrent les jours les plus tourmentés et les plus chers de ma vie. On ne l''avait pas encore vu quand une voiture de paysan s''arrêta devant le portail rouillé de la cour. Un gamin inconnu sauta du marchepied avec agilité. Il portait un costume de collégien : une blouse noire serrée à la ceinture par un ceinturon de cuir, et des pantalons serrés au-dessous du genou par des jambières boutonnées. Je pus remarquer qu''il avait des souliers fins, recouverts de boue. Nous ne l''avions pas encore vu que, déjà, la pensée de ce nouveau compagnon suffisait à me troubler. — Alain-Fournier, Le Grand Meaulnes (1913), chapitre I',
  '[{"id":"a","label":"Dérivation suffixale : nom « rouille » + suffixe adjectival « -é »"},{"id":"b","label":"Composition de deux mots : « rouil » + « lé »"},{"id":"c","label":"Emprunt à l''anglais « rusty »"},{"id":"d","label":"Conversion (changement de catégorie sans modification)"}]'::jsonb,
  '{"mode":"single_choice","value":"a"}'::jsonb,
  '« Rouillé » est formé par dérivation suffixale : le nom « rouille » + le suffixe « -é » qui transforme un nom en adjectif (ou participe passé du verbe « rouiller »). Ce suffixe « -é » est très productif : sucre → sucré, beurre → beurré, rouille → rouillé. Il exprime la présence de la substance ou la qualité désignée par le nom de base. L''analyse de la formation des mots par dérivation est un attendu du CRPE.',
  'Parler de conversion (changement de catégorie sans modification de forme). Ici, il y a bien ajout d''un suffixe « -é » au nom « rouille ».',
  'valide', 'CRPE Français — Sujet blanc n°1', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- ============================================================
-- SUJET BLANC N°2 — Colette, Sido (1930)
-- Texte : portrait de Sido au jardin
-- ============================================================

-- ── PARTIE 1 · ÉTUDE DE LA LANGUE ──────────────────────────

-- Q1 — grammaire — Intermediaire — qcm — Fonction de « à travers le jardin »
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-000000000001',
  'Francais', 'grammaire', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Intermediaire', 'qcm',
  'Quelle est la fonction du groupe « à travers le jardin » dans « Elle avait coutume de distribuer à travers le jardin ses matinées de printemps » ?',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  '[{"id":"a","label":"Complément d''objet indirect du verbe « distribuer »"},{"id":"b","label":"Complément circonstanciel de lieu du verbe « distribuer »"},{"id":"c","label":"Complément du nom « matinées »"},{"id":"d","label":"Attribut du sujet « elle »"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  '« À travers le jardin » est un complément circonstanciel de lieu (CCL) du verbe « distribuer ». Ce groupe prépositionnel indique le lieu où se déroule l''action de distribuer les matinées. Il est mobile (on peut le déplacer : « À travers le jardin, elle avait coutume de distribuer ses matinées ») et supprimable, deux propriétés caractéristiques du complément circonstanciel. La locution prépositive « à travers » introduit un lieu traversé.',
  'Confondre le CCL avec un COI. Le COI complète le verbe de manière essentielle (non supprimable), tandis que « à travers le jardin » est un complément facultatif indiquant le cadre spatial.',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q2 — grammaire — Difficile — reponse_courte — Fonction de « dont »
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-000000000002',
  'Francais', 'grammaire', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Difficile', 'reponse_courte',
  'Dans « la montagne dont elle seule savait lire exactement les signes », quelle est la fonction du pronom relatif « dont » ?',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  NULL,
  '{"mode":"text","acceptableAnswers":["complément du nom signes","complement du nom signes","complément du nom « signes »","CDN de signes","complément du nom"]}'::jsonb,
  '« Dont » est un pronom relatif qui a pour antécédent « la montagne ». Dans la subordonnée relative, « dont » occupe la fonction de complément du nom « signes » : elle savait lire les signes DE LA MONTAGNE → dont. Le pronom « dont » remplace un complément introduit par « de ». L''analyse fine de la fonction de « dont » est un classique du CRPE : il peut être complément du nom, COI ou complément de l''adjectif selon le contexte.',
  'Analyser « dont » comme COI du verbe « savait » ou « lire ». En réalité, « dont » complète le nom « signes » (les signes de la montagne), pas le verbe.',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q3 — grammaire — Intermediaire — reponse_courte — Fonction de « D'un doigt précautionneux »
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-000000000003',
  'Francais', 'grammaire', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Intermediaire', 'reponse_courte',
  'Quelle est la fonction du groupe « D''un doigt précautionneux » dans « D''un doigt précautionneux, elle soulevait un pétale de rose » ?',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  NULL,
  '{"mode":"text","acceptableAnswers":["complément circonstanciel de manière","complément circonstanciel de moyen","CC de manière","CC de moyen","CCM","complement circonstanciel de maniere","complement circonstanciel de moyen"]}'::jsonb,
  '« D''un doigt précautionneux » est un complément circonstanciel de manière (ou de moyen) du verbe « soulevait ». Ce groupe prépositionnel, introduit par « de » (d''), indique avec quel instrument et de quelle façon l''action est réalisée. Il est mobile (placé en tête de phrase, détaché par une virgule) et supprimable, deux critères du complément circonstanciel. La frontière entre CC de moyen et CC de manière est parfois ténue ; les deux analyses sont acceptées au CRPE.',
  'Confondre avec un complément du nom ou un COI. « D''un doigt précautionneux » ne complète pas un nom mais le verbe « soulevait », et il est déplaçable, ce qui exclut le COI.',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q4 — grammaire — Difficile — qcm — Nature de « Venue de la buanderie »
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-000000000004',
  'Francais', 'grammaire', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Difficile', 'qcm',
  'Quelle est la nature de « Venue de la buanderie » dans la phrase « Venue de la buanderie, elle regardait si la glycine avait épaissi son feuillage » ?',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  '[{"id":"a","label":"Proposition subordonnée participiale à sujet propre"},{"id":"b","label":"Participe passé employé comme adjectif apposé au sujet, à valeur circonstancielle"},{"id":"c","label":"Proposition subordonnée circonstancielle de temps"},{"id":"d","label":"Groupe nominal complément du nom « buanderie »"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  '« Venue de la buanderie » est un participe passé apposé au sujet « elle », avec une valeur circonstancielle (cause ou temps : parce qu''elle venait de la buanderie / après être venue de la buanderie). Ce n''est pas une proposition subordonnée participiale car il n''a pas de sujet propre (son sujet est le même que celui de la principale : « elle »). Le participe passé apposé, détaché en tête de phrase par une virgule, est une construction fréquente en littérature. Au CRPE, il faut savoir distinguer l''apposition participiale de la subordonnée participiale (qui possède un sujet différent de celui de la principale).',
  'Confondre avec une subordonnée participiale. La participiale a un sujet propre (ex. « La pluie ayant cessé, elle sortit »). Ici, le sujet du participe est le même que celui du verbe principal (« elle »).',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q5 — grammaire — Difficile — qcm — Nature de « si la glycine avait épaissi son feuillage »
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-000000000005',
  'Francais', 'grammaire', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Difficile', 'qcm',
  'Quelle est la nature de la proposition « si la glycine avait épaissi son feuillage » dans « elle regardait si la glycine avait épaissi son feuillage » ?',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  '[{"id":"a","label":"Proposition subordonnée circonstancielle de condition"},{"id":"b","label":"Proposition subordonnée conjonctive complétive (interrogative indirecte)"},{"id":"c","label":"Proposition subordonnée relative"},{"id":"d","label":"Proposition indépendante coordonnée"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  '« Si la glycine avait épaissi son feuillage » est une proposition subordonnée conjonctive complétive, plus précisément une interrogative indirecte totale. Elle est COD du verbe « regardait » (regarder si = chercher à savoir si). Le mot « si » est ici un adverbe interrogatif (= est-ce que), et non la conjonction de condition. L''interrogative indirecte totale est introduite par « si » et correspond à une question fermée (oui/non). Au CRPE, il est essentiel de distinguer le « si » interrogatif (complétive) du « si » conditionnel (circonstancielle).',
  'Confondre l''interrogative indirecte avec une circonstancielle de condition. Le test : « elle regardait si… » = elle cherchait à savoir si… (question indirecte). Si c''était une condition, on aurait : « si la glycine avait épaissi, elle serait sortie » (avec un conditionnel dans la principale).',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q6 — orthographe — Intermediaire — qcm — Accord avec sujet composé
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-000000000006',
  'Francais', 'orthographe', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Intermediaire', 'qcm',
  'Dans « pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas », pourquoi le verbe « logeaient » est-il au pluriel ?',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  '[{"id":"a","label":"Parce que le sujet « y » est un pronom pluriel"},{"id":"b","label":"Parce que le verbe s''accorde avec le sujet composé formé de trois groupes nominaux juxtaposés (la bête noire, le puceron vert, le scarabée mordoré)"},{"id":"c","label":"Parce que le verbe pronominal « se loger » est toujours au pluriel"},{"id":"d","label":"Parce que « pas » entraîne un accord au pluriel"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  'Le verbe « logeaient » est au pluriel car son sujet est un sujet composé formé de trois groupes nominaux juxtaposés par des virgules : « la bête noire, le puceron vert, le scarabée mordoré ». Quand plusieurs GN sont coordonnés ou juxtaposés en fonction sujet, le verbe se met au pluriel (3 sujets singuliers = pluriel). C''est la règle de l''accord avec le sujet composé. Le « y » est un pronom adverbial (complément de lieu reprenant « un pétale de rose »), pas le sujet.',
  'Croire que chaque GN est un sujet indépendant nécessitant un verbe propre, ou analyser « y » comme le sujet. Les trois GN forment ensemble un sujet composé unique qui commande le pluriel.',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q7 — analyse_langue — Difficile — qcm — Fonction de « qui » dans la relative
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-000000000007',
  'Francais', 'analyse_langue', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Difficile', 'qcm',
  'Dans « l''écharpe de nuages qui s''enroulait à son faîte », quelle est la fonction du pronom relatif « qui » ?',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  '[{"id":"a","label":"Complément d''objet direct de « s''enroulait »"},{"id":"b","label":"Complément circonstanciel de lieu"},{"id":"c","label":"Sujet du verbe « s''enroulait »"},{"id":"d","label":"Attribut du sujet « écharpe »"}]'::jsonb,
  '{"mode":"single_choice","value":"c"}'::jsonb,
  'Le pronom relatif « qui » est sujet du verbe pronominal « s''enroulait » dans la subordonnée relative. Son antécédent est « l''écharpe de nuages ». Règle fondamentale : le pronom relatif « qui » est toujours sujet du verbe de la relative. C''est le critère le plus fiable pour distinguer « qui » sujet de « que » COD. Le verbe de la relative s''accorde avec l''antécédent via « qui » : « l''écharpe… qui s''enroulait » (3e personne du singulier, car « écharpe » est singulier).',
  'Analyser « qui » comme COD ou confondre l''antécédent. « Qui » est toujours sujet dans la relative. L''antécédent est « l''écharpe de nuages » (et non « nuages » seul), ce qui justifie le singulier du verbe.',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q8 — grammaire — Difficile — reponse_courte — RÉÉCRITURE elle → elles
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-000000000008',
  'Francais', 'grammaire', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Difficile', 'reponse_courte',
  'RÉÉCRITURE — Réécrivez la phrase suivante en remplaçant « elle » par « elles » (3e personne du féminin pluriel). Effectuez toutes les modifications nécessaires : « Venue de la buanderie, elle regardait si la glycine avait épaissi son feuillage. »',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  NULL,
  '{"mode":"text","acceptableAnswers":["Venues de la buanderie, elles regardaient si la glycine avait épaissi son feuillage.","Venues de la buanderie, elles regardaient si la glycine avait épaissi son feuillage"]}'::jsonb,
  'Les modifications sont : « Venue » → « Venues » (accord du participe passé apposé au féminin pluriel) ; « elle » → « elles » (pronom personnel sujet féminin pluriel) ; « regardait » → « regardaient » (accord du verbe à l''imparfait, 3e personne du pluriel). La subordonnée « si la glycine avait épaissi son feuillage » ne change pas car son sujet (« la glycine ») est indépendant du sujet principal.',
  'Oublier d''accorder le participe passé apposé « Venue » au pluriel. « Venue » s''accorde avec le sujet « elles » : Venues (féminin pluriel). C''est un piège classique des exercices de réécriture au CRPE.',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q9 — grammaire — Difficile — reponse_courte — RÉÉCRITURE voix passive
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-000000000009',
  'Francais', 'grammaire', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Difficile', 'reponse_courte',
  'RÉÉCRITURE — Mettez la phrase suivante à la voix passive : « Elle arrachait les chiendents d''une main leste. »',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  NULL,
  '{"mode":"text","acceptableAnswers":["Les chiendents étaient arrachés d''une main leste par elle.","Les chiendents étaient arrachés d''une main leste par elle","Les chiendents étaient arrachés par elle d''une main leste.","Les chiendents étaient arrachés par elle d''une main leste"]}'::jsonb,
  'À la voix passive : le COD « les chiendents » devient sujet ; le verbe passe à la forme passive « étaient arrachés » (auxiliaire « être » à l''imparfait + participe passé, avec accord au masculin pluriel) ; le sujet actif « elle » devient complément d''agent introduit par « par ». Le CC de manière « d''une main leste » reste inchangé. L''imparfait actif (« arrachait ») se conserve à la voix passive (« étaient arrachés »).',
  'Oublier d''accorder le participe passé « arrachés » avec le nouveau sujet « les chiendents » (masculin pluriel). Ou ne pas conserver l''imparfait dans la transformation passive.',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q10 — grammaire — Difficile — reponse_courte — RÉÉCRITURE elle → elles (phrase longue)
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-00000000000a',
  'Francais', 'grammaire', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Difficile', 'reponse_courte',
  'RÉÉCRITURE — Réécrivez la phrase suivante en remplaçant « elle » par « elles » (3e personne du féminin pluriel). Effectuez toutes les modifications nécessaires : « Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait le parfum d''une feuille de cassis. »',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  NULL,
  '{"mode":"text","acceptableAnswers":["Accroupies, elles arrachaient les chiendents d''une main leste, redressaient d''un tuteur la tige d''un œillet, et respiraient le parfum d''une feuille de cassis.","Accroupies, elles arrachaient les chiendents d''une main leste, redressaient d''un tuteur la tige d''un œillet, et respiraient le parfum d''une feuille de cassis"]}'::jsonb,
  'Les modifications sont : « Accroupie » → « Accroupies » (participe passé apposé, accord au féminin pluriel) ; « elle » → « elles » (pronom sujet féminin pluriel) ; « arrachait » → « arrachaient », « redressait » → « redressaient », « respirait » → « respiraient » (trois verbes coordonnés à l''imparfait, accord au pluriel). Les compléments « les chiendents », « d''une main leste », « d''un tuteur », « la tige d''un œillet », « le parfum d''une feuille de cassis » restent inchangés car ils ne dépendent pas du sujet.',
  'Oublier d''accorder « Accroupie » au pluriel, ou ne modifier qu''un seul des trois verbes coordonnés. Les trois verbes (arrachait, redressait, respirait) ont le même sujet « elle » et doivent tous passer au pluriel.',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q11 — orthographe — Intermediaire — qcm — Accord de l'épithète détachée
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-00000000000b',
  'Francais', 'orthographe', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Intermediaire', 'qcm',
  'Dans « les premiers radis, nacrés de rose, sortaient de terre », pourquoi « nacrés » est-il au masculin pluriel ?',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  '[{"id":"a","label":"Parce que « nacrés » est un adverbe invariable placé après le nom"},{"id":"b","label":"Parce que « nacrés » est une épithète détachée (apposée) qui s''accorde avec « radis » (masculin pluriel)"},{"id":"c","label":"Parce que « nacrés » s''accorde avec « rose » qui est au pluriel"},{"id":"d","label":"Parce que le participe passé avec « être » sous-entendu est toujours au pluriel"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  '« Nacrés » est un adjectif (ou participe passé adjectivé) employé comme épithète détachée (apposée). Il est séparé du nom par des virgules et s''accorde en genre et en nombre avec le nom auquel il se rapporte : « radis » (masculin pluriel). L''épithète détachée qualifie le nom tout en étant isolée par la ponctuation. Elle s''accorde toujours avec le nom ou le pronom qu''elle caractérise. « De rose » est un complément de l''adjectif (nacrés de quelle couleur ? de rose).',
  'Croire que « nacrés » s''accorde avec « rose ». « De rose » est un complément de l''adjectif, pas le donneur d''accord. C''est « radis » qui commande l''accord de « nacrés ».',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q12 — conjugaison — Intermediaire — qcm — Valeur du présent d'évocation
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-00000000000c',
  'Francais', 'conjugaison', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Intermediaire', 'qcm',
  'Dans « C''est elle encore que je vois, accoudée à la fenêtre », quelle est la valeur du présent de l''indicatif « vois » ?',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  '[{"id":"a","label":"Présent d''habitude (action répétée)"},{"id":"b","label":"Présent de narration (action passée racontée au présent)"},{"id":"c","label":"Présent d''évocation / de mémoire (souvenir revécu au présent)"},{"id":"d","label":"Présent de vérité générale"}]'::jsonb,
  '{"mode":"single_choice","value":"c"}'::jsonb,
  '« Je vois » est un présent d''évocation (ou de mémoire). La narratrice, Colette, se remémore sa mère Sido et la revoit en pensée au moment de l''écriture. L''adverbe « encore » renforce cette valeur : « C''est elle encore que je vois » = je la revois encore en souvenir. Ce présent s''insère dans un récit au passé (imparfait dominant) et crée un effet de proximité affective avec le souvenir. Il ne s''agit pas d''un présent de narration (qui remplacerait un passé simple pour dramatiser) ni d''un présent d''habitude.',
  'Confondre le présent d''évocation avec le présent de narration. Le présent de narration remplace un passé simple dans un récit pour accélérer le tempo. Le présent d''évocation exprime un souvenir qui revient à l''esprit du narrateur, souvent accompagné de marques affectives.',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- ── PARTIE 2 · ANALYSE DU LEXIQUE ──────────────────────────

-- Q13 — lexique — Intermediaire — qcm — Champ lexical dominant
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-00000000000d',
  'Francais', 'lexique', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Intermediaire', 'qcm',
  'Quel est le champ lexical dominant dans ce texte de Colette ?',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  '[{"id":"a","label":"La cuisine et la gastronomie"},{"id":"b","label":"La nature et le jardin"},{"id":"c","label":"L''architecture et la maison"},{"id":"d","label":"Le voyage et l''exploration"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  'Le champ lexical dominant est celui de la nature et du jardin. On relève de très nombreux termes appartenant à ce champ : « jardin », « glycine », « feuillage », « pétale », « rose », « fleurs », « graines », « terreau », « radis », « cassis », « tilleul », « bouture », « semis », « chiendents », « tuteur », « tige », « œillet », « feuille », « pluie », « terre », « mûrir », « germer ». Ce réseau lexical structure l''ensemble du texte et dessine le portrait de Sido à travers sa passion du jardinage.',
  'Choisir « l''architecture et la maison » en se fondant sur « buanderie » et « fenêtre ». Ces mots sont minoritaires et servent de cadre spatial, alors que le champ lexical végétal irrigue tout le texte.',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q14 — lexique — Intermediaire — reponse_courte — Relever 4 mots du champ lexical végétal
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-00000000000e',
  'Francais', 'lexique', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Intermediaire', 'reponse_courte',
  'Relevez quatre mots appartenant au champ lexical de la végétation dans ce texte.',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  NULL,
  '{"mode":"text","acceptableAnswers":["glycine, pétale, rose, graines","glycine, radis, cassis, tilleul","graines, radis, cassis, tilleul","pétale, rose, graines, radis","glycine, graines, bouture, semis","œillet, cassis, tilleul, chiendents","feuillage, pétale, rose, graines","glycine, feuillage, fleurs, graines","tige, œillet, feuille, cassis","bouture, semis, chiendents, œillet"]}'::jsonb,
  'Le texte contient de nombreux mots du champ lexical de la végétation : « glycine », « feuillage », « pétale », « rose », « fleurs », « graines », « radis », « cassis », « tilleul », « bouture », « semis », « chiendents », « tige », « œillet », « feuille ». Tout relevé de quatre mots parmi cette liste est accepté. Le champ lexical regroupe des mots de natures grammaticales variées (noms, verbes, adjectifs) partageant un même thème sémantique.',
  'Confondre champ lexical et champ sémantique, ou inclure des mots hors du champ végétal (comme « montagne », « pluie » ou « terre » qui relèvent davantage du champ de la nature au sens large).',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q15 — lexique — Difficile — qcm — Formation de « précautionneux »
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-00000000000f',
  'Francais', 'lexique', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Difficile', 'qcm',
  'Par quel procédé de formation le mot « précautionneux » est-il construit ?',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  '[{"id":"a","label":"Composition (assemblage de deux mots autonomes)"},{"id":"b","label":"Dérivation suffixale (base « précaution » + suffixe « -eux »)"},{"id":"c","label":"Dérivation préfixale (préfixe « pré- » + base « cautionneux »)"},{"id":"d","label":"Mot-valise (fusion de « précaution » et « soigneux »)"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  '« Précautionneux » est formé par dérivation suffixale : la base est le nom « précaution » et le suffixe est « -eux » (avec l''interfixe « -n- » : précaution-n-eux). Le suffixe « -eux/-euse » est un suffixe adjectival très productif en français qui transforme un nom en adjectif exprimant la qualité ou la possession : courage → courageux, danger → dangereux, précaution → précautionneux. Il ne s''agit pas d''une dérivation préfixale car « cautionneux » n''existe pas comme mot autonome.',
  'Analyser le mot comme une dérivation préfixale avec « pré- ». Le test est simple : « cautionneux » n''existe pas en français, donc « pré- » ne peut pas être un préfixe ajouté à une base existante. La base est bien « précaution » (mot existant) + suffixe « -eux ».',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q16 — lexique — Intermediaire — reponse_courte — Préfixe de « inexplicable »
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-000000000010',
  'Francais', 'lexique', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Intermediaire', 'reponse_courte',
  'Dans « l''inexplicable retard d''un semis », quel est le préfixe du mot « inexplicable » et quelle est sa valeur ?',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  NULL,
  '{"mode":"text","acceptableAnswers":["in- (négation)","in-, négation","in- : négation","préfixe in-, valeur de négation","in- négatif","in- de négation","in-, valeur négative"]}'::jsonb,
  'Le préfixe est « in- » et sa valeur est la négation. « Inexplicable » = qui ne peut pas être expliqué (in- + explicable). Le préfixe latin « in- » négatif est très productif en français : il se réalise sous différentes formes selon la consonne qui suit : « in- » devant voyelle ou consonne (inexplicable, inconnu), « im- » devant b, m, p (impossible, immeuble), « il- » devant l (illisible), « ir- » devant r (irréel). À ne pas confondre avec le « in- » locatif (infiltrer, inclure = mettre dedans).',
  'Confondre la valeur négative du préfixe « in- » avec sa valeur locative (« dans »). Ici, « inexplicable » signifie « pas explicable » (négation), et non « à l''intérieur de quelque chose ».',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q17 — lexique — Difficile — qcm — Figure de style : métaphore
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-000000000011',
  'Francais', 'lexique', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Difficile', 'qcm',
  'Quelle figure de style est employée dans « l''écharpe de nuages qui s''enroulait à son faîte » ?',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  '[{"id":"a","label":"Comparaison"},{"id":"b","label":"Métaphore"},{"id":"c","label":"Hyperbole"},{"id":"d","label":"Métonymie"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  '« L''écharpe de nuages » est une métaphore. Les nuages sont désignés par le terme « écharpe » sans outil de comparaison (pas de « comme », « tel que », « semblable à »). La métaphore repose sur l''analogie de forme : les nuages s''étirent et s''enroulent autour du sommet de la montagne comme une écharpe autour d''un cou. Le verbe « s''enroulait » prolonge l''image en filant la métaphore textile. La distinction entre métaphore (sans outil comparatif) et comparaison (avec outil comparatif) est un attendu fondamental du CRPE.',
  'Confondre métaphore et comparaison. La comparaison utilise un outil comparatif explicite (« comme une écharpe »). Ici, l''identification est directe : les nuages SONT une écharpe. C''est donc une métaphore.',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q18 — lexique — Difficile — qcm — Figure de style : personnification
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-000000000012',
  'Francais', 'lexique', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Difficile', 'qcm',
  'Quel procédé stylistique est utilisé dans « l''ingratitude d''une bouture obstinée à mourir » ?',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  '[{"id":"a","label":"Comparaison"},{"id":"b","label":"Antithèse"},{"id":"c","label":"Personnification"},{"id":"d","label":"Litote"}]'::jsonb,
  '{"mode":"single_choice","value":"c"}'::jsonb,
  'Il s''agit d''une personnification. La bouture (un végétal) se voit attribuer des qualités humaines : « l''ingratitude » (sentiment humain) et « obstinée » (trait de caractère volontaire). Colette prête à la plante une intention et un défaut moral, comme si la bouture refusait délibérément de vivre malgré les soins prodigués. La personnification consiste à attribuer des caractéristiques humaines (sentiments, comportements, parole) à un être non humain, un animal ou un objet. Ce procédé révèle ici le lien affectif de Sido avec ses plantes.',
  'Confondre personnification et métaphore. La métaphore établit une analogie entre deux réalités différentes. La personnification, plus spécifique, attribue des traits humains à un non-humain. Ici, c''est bien une personnification car la bouture est dotée de sentiments (ingratitude) et de volonté (obstinée).',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q19 — lexique — Intermediaire — qcm — Sens de « translucide »
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-000000000013',
  'Francais', 'lexique', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Intermediaire', 'qcm',
  'Quel est le sens du mot « translucide » dans « une brume translucide » ?',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  '[{"id":"a","label":"Qui est totalement opaque et sombre"},{"id":"b","label":"Qui laisse passer la lumière sans être transparent"},{"id":"c","label":"Qui est parfaitement transparent comme du verre"},{"id":"d","label":"Qui brille d''un éclat vif et coloré"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  '« Translucide » signifie « qui laisse passer la lumière sans permettre de distinguer nettement les objets à travers ». C''est un degré intermédiaire entre opaque (ne laisse pas passer la lumière) et transparent (laisse voir nettement à travers). Le mot vient du latin « translucidus » (trans = à travers + lucidus = lumineux). Appliqué à la brume, il évoque une brume légère, lumineuse, à travers laquelle la lumière filtre sans que les formes soient nettes.',
  'Confondre « translucide » et « transparent ». Un objet transparent laisse voir nettement les objets (une vitre). Un objet translucide laisse passer la lumière mais pas les formes nettes (un verre dépoli, du papier calque). La brume est translucide : lumineuse mais floue.',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q20 — lexique — Difficile — qcm — Relation lexicale synonymie
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6020000-0000-0000-0000-000000000014',
  'Francais', 'lexique', 'sujet_blanc_crpe_2', 'Sujet blanc n°2 — Sido', 'Difficile', 'qcm',
  'Quelle relation lexicale unit les mots « buanderie » et « laverie » ?',
  'Elle avait coutume de distribuer à travers le jardin ses matinées de printemps. Venue de la buanderie, elle regardait si la glycine avait, entre deux pluies, épaissi son feuillage. D''un doigt précautionneux, elle soulevait un pétale de rose pour voir si la bête noire, le puceron vert, le scarabée mordoré ne s''y logeaient pas. C''est elle encore que je vois, accoudée à la fenêtre, interrogeant l''horizon du côté de l''est, du côté de la montagne dont elle seule savait lire exactement les signes : un bleu orageux, une brume translucide, l''écharpe de nuages qui s''enroulait à son faîte… — Je crois bien qu''il va pleuvoir, soupirait-elle. Car elle aimait le beau temps pour ses fleurs, et la pluie parce qu''elle remplissait les citernes. Elle avait fait de son jardin un lieu d''enchantement et de patience. Les graines, qu''elle semait dans le terreau fin d''un châssis abrité, germaient fidèlement, et les premiers radis, nacrés de rose, sortaient de terre à l''heure dite. Elle savait le moment où le cassis allait mûrir et quand le tilleul livrerait ses fleurs blondes à la dessiccation. Rien ne l''étonnait au jardin, sinon parfois l''ingratitude d''une bouture obstinée à mourir, ou l''inexplicable retard d''un semis. Accroupie, elle arrachait les chiendents d''une main leste, redressait d''un tuteur la tige d''un œillet, et respirait, au passage, le parfum d''une feuille de cassis. — Colette, Sido (1930)',
  '[{"id":"a","label":"Antonymie (sens contraires)"},{"id":"b","label":"Synonymie (ou parasyonymie : sens très proches)"},{"id":"c","label":"Hyperonymie (l''un inclut l''autre)"},{"id":"d","label":"Homonymie (même forme, sens différents)"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  '« Buanderie » et « laverie » sont des synonymes (ou plus précisément des parasynonymes). Les deux mots désignent un lieu où l''on lave le linge, mais avec des nuances : « buanderie » désigne traditionnellement la pièce de la maison réservée à la lessive, tandis que « laverie » peut aussi désigner un établissement commercial (laverie automatique). En linguistique, la synonymie parfaite est rare ; on parle de parasynonymie quand les mots sont interchangeables dans certains contextes mais pas tous. Au CRPE, les deux termes (synonymes / parasynonymes) sont acceptés.',
  'Choisir l''hyperonymie. L''hyperonymie implique une relation d''inclusion (« meuble » est l''hyperonyme de « chaise »). Or « buanderie » n''inclut pas « laverie » ni l''inverse : les deux mots sont au même niveau sémantique, ce sont des synonymes.',
  'valide', 'CRPE Français — Sujet blanc n°2', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- ============================================================
-- SUJET BLANC N°3 — Jules Vallès, L'Enfant (1879)
-- Texte : l'enfant et les animaux
-- ============================================================

-- ── PARTIE 1 · ÉTUDE DE LA LANGUE ──────────────────────────

-- Q1 — grammaire — Intermediaire — qcm — Nature d'une proposition
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000001',
  'Francais', 'grammaire', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Intermediaire', 'qcm',
  'Dans « Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes », quelle est la nature de la proposition « qu''on aime les bêtes » ?',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  '[{"id":"a","label":"Proposition subordonnée conjonctive complétive (COD de « montrer »)"},{"id":"b","label":"Proposition subordonnée relative"},{"id":"c","label":"Proposition subordonnée circonstancielle de cause"},{"id":"d","label":"Proposition indépendante coordonnée"}]'::jsonb,
  '{"mode":"single_choice","value":"a"}'::jsonb,
  '« Qu''on aime les bêtes » est une proposition subordonnée conjonctive complétive, COD de l''infinitif « montrer » (montrer quoi ? → qu''on aime les bêtes). Elle est introduite par la conjonction de subordination « que ». La conjonction « que » n''a pas d''antécédent nominal (contrairement au pronom relatif « que ») et n''occupe aucune fonction à l''intérieur de la subordonnée. La distinction entre conjonction de subordination et pronom relatif est un attendu essentiel du CRPE.',
  'Confondre la conjonctive complétive avec une relative. Ici, « que » est conjonction de subordination (pas d''antécédent nominal), et non pronom relatif.',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q2 — grammaire — Intermediaire — qcm — Fonction de relatives
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000002',
  'Francais', 'grammaire', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Intermediaire', 'qcm',
  'Quelle est la fonction des propositions relatives « qui sent le chenil, qui a des taches fauves au-dessus des yeux » dans le texte ?',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  '[{"id":"a","label":"Compléments d''objet directs du verbe « sentir »"},{"id":"b","label":"Expansions du nom « chien » (fonction épithète)"},{"id":"c","label":"Compléments circonstanciels de manière"},{"id":"d","label":"Attributs du sujet « chien »"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  'Les propositions relatives « qui sent le chenil » et « qui a des taches fauves au-dessus des yeux » sont des expansions du nom « chien ». Elles occupent la fonction d''épithète (ou complément de l''antécédent) : elles caractérisent le GN « ce grand chien noir » en ajoutant des informations descriptives. Ces relatives sont dites explicatives (appositives) car elles enrichissent la description sans restreindre l''identification du référent. Savoir identifier la fonction des propositions relatives comme expansions du nom est un attendu du CRPE.',
  'Confondre la fonction de la relative (expansion du nom / épithète) avec la fonction du pronom relatif « qui » (sujet du verbe de la relative). La relative dans son ensemble complète le nom « chien ».',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q3 — grammaire — Intermediaire — reponse_courte — Fonction d'un groupe
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000003',
  'Francais', 'grammaire', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Intermediaire', 'reponse_courte',
  'Quelle est la fonction du groupe prépositionnel « vers la maison » dans « en me traînant par le bras vers la maison » ?',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  NULL,
  '{"mode":"text","acceptableAnswers":["complément circonstanciel de lieu","complement circonstanciel de lieu","CCL","ccl","CC de lieu","cc de lieu","complément circonstanciel de lieu de traînant","CCL de traînant"]}'::jsonb,
  '« Vers la maison » est un complément circonstanciel de lieu (CCL). Il indique la direction du mouvement exprimé par le gérondif « en traînant ». Introduit par la préposition « vers » (qui marque la direction), ce groupe prépositionnel est mobile et supprimable, ce qui confirme son statut de complément circonstanciel. Il répond à la question « vers où ? ». La distinction entre CCL et complément essentiel de lieu (non supprimable) est importante au CRPE.',
  'Confondre le CCL avec un COI ou un complément du nom. « Vers la maison » ne complète pas un nom mais indique la direction du déplacement.',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q4 — grammaire — Difficile — qcm — Type de discours rapporté
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000004',
  'Francais', 'grammaire', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Difficile', 'qcm',
  'Dans « Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes », quel type de discours rapporté est utilisé ?',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  '[{"id":"a","label":"Discours direct"},{"id":"b","label":"Discours indirect"},{"id":"c","label":"Discours indirect libre"},{"id":"d","label":"Discours narrativisé"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  'Il s''agit d''un discours indirect. Les paroles de la mère sont rapportées par le narrateur via un verbe introducteur (« dit ») suivi de la conjonction « que ». En discours direct, on aurait : Ma mère dit : « C''est dégoûtant de montrer qu''on aime les bêtes. » Le discours indirect se caractérise par l''absence de guillemets, la présence d''un mot subordonnant (« que ») et l''intégration syntaxique des paroles dans la phrase du narrateur. À noter que plus loin dans le texte, « Sale enfant ! » crie-t-elle est en revanche du discours direct (guillemets, exclamation, inversion sujet-verbe).',
  'Confondre avec le discours direct. Le discours direct utilise des guillemets et reproduit les paroles telles quelles. Ici, les paroles sont intégrées à la phrase du narrateur par « que ».',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q5 — grammaire — Difficile — qcm — Nature d'une subordonnée
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000005',
  'Francais', 'grammaire', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Difficile', 'qcm',
  'Dans « Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête », quelle est la nature de la proposition « où j''ai le nez dans le poil de la bête » ?',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  '[{"id":"a","label":"Proposition subordonnée conjonctive circonstancielle de temps"},{"id":"b","label":"Proposition subordonnée conjonctive complétive"},{"id":"c","label":"Proposition subordonnée relative (« où » pronom relatif, antécédent « moment »)"},{"id":"d","label":"Proposition indépendante juxtaposée"}]'::jsonb,
  '{"mode":"single_choice","value":"c"}'::jsonb,
  '« Où j''ai le nez dans le poil de la bête » est une proposition subordonnée relative. Le mot « où » est ici un pronom relatif (et non une conjonction) car il a un antécédent nominal : « moment ». Le pronom relatif « où » remplace « au moment » et occupe la fonction de complément circonstanciel de temps dans la subordonnée. La relative complète le nom « moment » en tant qu''expansion du nom. Au CRPE, il est essentiel de distinguer « où » pronom relatif (avec antécédent) de « où » adverbe interrogatif.',
  'Confondre avec une circonstancielle de temps. La présence d''un antécédent (« moment ») prouve qu''il s''agit d''une relative introduite par le pronom relatif « où », et non d''une conjonctive.',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q6 — analyse_langue — Intermediaire — qcm — Nature du gérondif
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000006',
  'Francais', 'analyse_langue', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Intermediaire', 'qcm',
  'Dans « Il faisait un bruit de tambour en cognant contre les parois de sa prison », quelle est la nature de « en cognant » ?',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  '[{"id":"a","label":"Un participe présent employé comme adjectif"},{"id":"b","label":"Un infinitif prépositionnel"},{"id":"c","label":"Un gérondif (CC de manière / simultanéité)"},{"id":"d","label":"Une proposition subordonnée circonstancielle"}]'::jsonb,
  '{"mode":"single_choice","value":"c"}'::jsonb,
  '« En cognant » est un gérondif, formé de la préposition « en » + le participe présent « cognant ». Il fonctionne comme complément circonstanciel exprimant la manière et la simultanéité : il indique comment et en même temps que quoi le hanneton faisait du bruit. Le gérondif a toujours le même sujet que le verbe principal (ici, « il » = le hanneton). Il se distingue du participe présent employé seul (sans « en ») qui peut avoir une valeur adjectivale. L''identification du gérondif et sa distinction avec le participe présent sont des notions attendues au CRPE.',
  'Confondre le gérondif avec un simple participe présent. Le gérondif est obligatoirement précédé de « en » et fonctionne comme CC. Le participe présent seul (« cognant ») n''est pas un gérondif.',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q7 — conjugaison — Difficile — qcm — Temps verbal
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000007',
  'Francais', 'conjugaison', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Difficile', 'qcm',
  'Dans « le hanneton s''est envolé, lourd et doré », à quel temps est conjugué le verbe « s''est envolé » ?',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  '[{"id":"a","label":"Passé simple de l''indicatif"},{"id":"b","label":"Plus-que-parfait de l''indicatif"},{"id":"c","label":"Passé composé de l''indicatif"},{"id":"d","label":"Imparfait de l''indicatif"}]'::jsonb,
  '{"mode":"single_choice","value":"c"}'::jsonb,
  '« S''est envolé » est au passé composé de l''indicatif. C''est un verbe pronominal (s''envoler) conjugué avec l''auxiliaire « être » au présent (« est ») + le participe passé « envolé ». Les verbes pronominaux se conjuguent toujours avec « être » aux temps composés. Attention à ne pas confondre avec le passé simple (qui serait « s''envola ») ni avec le plus-que-parfait (qui serait « s''était envolé »). La maîtrise des temps composés et de la conjugaison des verbes pronominaux est un attendu fondamental du CRPE.',
  'Confondre le passé composé avec le passé simple. « S''est envolé » = auxiliaire « être » au présent + participe passé → passé composé. Le passé simple serait « s''envola » (forme simple, sans auxiliaire).',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q8 — grammaire — Difficile — reponse_courte — Réécriture (je → nous)
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000008',
  'Francais', 'grammaire', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Difficile', 'reponse_courte',
  'RÉÉCRITURE — Réécrivez la phrase suivante en remplaçant « je » par « nous » (effectuez toutes les modifications nécessaires) : « je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. »',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  NULL,
  '{"mode":"text","acceptableAnswers":["nous courons après les papillons, nous nous arrêtons devant les nids, nous écrasons les mouches pour les araignées.","nous courons après les papillons, nous nous arrêtons devant les nids, nous écrasons les mouches pour les araignées","Nous courons après les papillons, nous nous arrêtons devant les nids, nous écrasons les mouches pour les araignées."]}'::jsonb,
  'En remplaçant « je » par « nous », il faut modifier : 1) « je cours » → « nous courons » (1re personne du pluriel, présent) ; 2) « je m''arrête » → « nous nous arrêtons » (le pronom réfléchi « me » devient « nous », et la terminaison du verbe change) ; 3) « j''écrase » → « nous écrasons ». Tous les verbes passent à la 1re personne du pluriel. Pour le verbe pronominal « s''arrêter », le changement du pronom réfléchi (me → nous) est un piège classique au CRPE. La réécriture teste la maîtrise des conjugaisons et des accords pronominaux.',
  'Oublier de modifier le pronom réfléchi dans « nous nous arrêtons ». Écrire « nous m''arrêtons » ou « nous arrêtons » (sans le pronom réfléchi) est une erreur fréquente.',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q9 — grammaire — Difficile — reponse_courte — Réécriture (voix passive)
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000009',
  'Francais', 'grammaire', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Difficile', 'reponse_courte',
  'RÉÉCRITURE — Transposez à la voix passive : « Elle a pris le cornet. »',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  NULL,
  '{"mode":"text","acceptableAnswers":["Le cornet a été pris par elle.","Le cornet a été pris par elle","le cornet a été pris par elle.","le cornet a été pris par elle"]}'::jsonb,
  'À la voix passive, le COD de la phrase active (« le cornet ») devient sujet, et le sujet actif (« elle ») devient complément d''agent introduit par « par ». Le verbe « a pris » (passé composé actif) se transforme en « a été pris » (passé composé passif = auxiliaire « être » au passé composé + participe passé « pris »). Le participe passé « pris » s''accorde avec le nouveau sujet « le cornet » (masculin singulier → pas de marque visible). La transformation passive conserve le temps du verbe : passé composé actif → passé composé passif.',
  'Oublier de conserver le temps (passé composé). Écrire « Le cornet est pris par elle » (présent passif) au lieu de « Le cornet a été pris par elle » (passé composé passif) est l''erreur la plus courante.',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q10 — grammaire — Difficile — reponse_courte — Réécriture (passé simple)
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000010',
  'Francais', 'grammaire', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Difficile', 'reponse_courte',
  'RÉÉCRITURE — Transposez au passé simple : « Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré. »',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  NULL,
  '{"mode":"text","acceptableAnswers":["Elle prit le cornet, l''ouvrit d''un coup sec, et le hanneton s''envola, lourd et doré.","Elle prit le cornet, l''ouvrit d''un coup sec, et le hanneton s''envola, lourd et doré","elle prit le cornet, l''ouvrit d''un coup sec, et le hanneton s''envola, lourd et doré.","elle prit le cornet, l''ouvrit d''un coup sec, et le hanneton s''envola, lourd et doré"]}'::jsonb,
  'Il faut transposer trois passés composés au passé simple : 1) « a pris » → « prit » (prendre, 3e groupe, passé simple en -it) ; 2) « a ouvert » → « ouvrit » (ouvrir, 3e groupe, passé simple en -it) ; 3) « s''est envolé » → « s''envola » (s''envoler, 1er groupe, passé simple en -a). Les adjectifs apposés « lourd et doré » ne changent pas car ils ne sont pas affectés par le temps verbal. Le passé simple est un temps simple (une seule forme verbale) qui exprime une action achevée dans le passé, souvent utilisé dans le récit littéraire. Sa maîtrise est un attendu essentiel du CRPE.',
  'Erreur fréquente : confondre les terminaisons du passé simple selon les groupes. « Prendre » et « ouvrir » (3e groupe) font « prit » et « ouvrit » (en -it), tandis que « s''envoler » (1er groupe) fait « s''envola » (en -a).',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q11 — orthographe — Difficile — qcm — « t » euphonique
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000011',
  'Francais', 'orthographe', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Difficile', 'qcm',
  'Dans « crie-t-elle », pourquoi un « t » apparaît-il entre tirets ?',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  '[{"id":"a","label":"C''est le pronom personnel « t'' » (forme élidée de « tu »)"},{"id":"b","label":"C''est un « t » euphonique pour éviter le hiatus entre deux voyelles"},{"id":"c","label":"C''est la marque de la 3e personne du singulier"},{"id":"d","label":"C''est une erreur typographique, il ne devrait pas y être"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  'Le « t » dans « crie-t-elle » est un « t » euphonique (ou analogique). Il est inséré entre le verbe « crie » (qui se termine par la voyelle « e ») et le pronom sujet inversé « elle » (qui commence par une voyelle) afin d''éviter le hiatus, c''est-à-dire la rencontre désagréable de deux sons vocaliques. Ce « t » n''a aucune valeur grammaticale : il ne représente ni un pronom ni une désinence verbale. On le retrouve dans les mêmes conditions avec d''autres verbes du 1er groupe à la 3e personne : « parle-t-il », « mange-t-on ». Il est toujours encadré par deux tirets. Ce phénomène est à distinguer du « -t » final de « dit-elle » ou « prend-il », où le « t » appartient à la forme verbale elle-même.',
  'Croire que le « t » est le pronom « t'' » (élision de « tu »). Ce « t » n''est pas un pronom ; il est purement phonétique et n''a aucune fonction grammaticale.',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q12 — conjugaison — Intermediaire — qcm — Valeur du présent
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000012',
  'Francais', 'conjugaison', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Intermediaire', 'qcm',
  'Dans ce texte, quelle est la valeur dominante du présent de l''indicatif utilisé par le narrateur (« je cours », « je m''arrête », « j''écrase ») ?',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  '[{"id":"a","label":"Présent d''énonciation (moment où l''on parle)"},{"id":"b","label":"Présent de narration (événements passés racontés au présent)"},{"id":"c","label":"Présent de vérité générale"},{"id":"d","label":"Présent d''habitude (actions répétées régulièrement)"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  'Le présent utilisé ici est un présent de narration. Le narrateur adulte (Jules Vallès) raconte des souvenirs d''enfance (événements passés) en utilisant le présent pour rendre le récit plus vivant et donner au lecteur l''impression de revivre les scènes. Les indices sont : le contexte autobiographique (souvenirs d''enfance), l''alternance avec des temps du passé (« j''avais attrapé », « il faisait », « s''est envolé »), et le verbe « Je me rappelle » qui signale un retour en arrière. Le présent de narration (ou présent historique) est un effet stylistique courant en littérature. On pourrait aussi considérer une valeur d''habitude (« Ma mère arrive toujours »), mais la valeur dominante dans l''ensemble du texte est narrative.',
  'Confondre le présent de narration avec le présent d''habitude. Bien que « toujours » suggère une habitude pour certaines phrases, l''ensemble du passage raconte des scènes passées au présent (valeur narrative dominante).',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- ── PARTIE 2 · ANALYSE DU LEXIQUE ──────────────────────────

-- Q13 — lexique — Intermediaire — qcm — Champ lexical
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000013',
  'Francais', 'lexique', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Intermediaire', 'qcm',
  'À quel champ lexical appartiennent les mots « papillons, nids, mouches, araignées, chien, hanneton » ?',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  '[{"id":"a","label":"Le champ lexical de la nature et du jardin"},{"id":"b","label":"Le champ lexical des animaux et des insectes"},{"id":"c","label":"Le champ lexical de la chasse"},{"id":"d","label":"Le champ lexical de la campagne"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  'Ces mots appartiennent au champ lexical des animaux et des insectes. Un champ lexical regroupe l''ensemble des mots qui se rapportent à un même thème ou une même notion. Ici : « papillons » (insecte), « nids » (habitat animal), « mouches » (insecte), « araignées » (arachnide), « chien » (mammifère), « hanneton » (insecte). On peut y ajouter « bêtes », « poil », « babine », « chenil ». Ce champ lexical est central dans le texte car il traduit l''amour de l''enfant pour les animaux, en opposition avec le dégoût maternel.',
  'Confondre champ lexical et champ sémantique. Le champ lexical regroupe des mots de différentes natures (noms, verbes, adjectifs) autour d''un même thème. Le champ sémantique concerne les différents sens d''un même mot.',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q14 — lexique — Intermediaire — reponse_courte — Relever un champ lexical
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000014',
  'Francais', 'lexique', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Intermediaire', 'reponse_courte',
  'Relevez quatre mots du texte appartenant au champ lexical des animaux.',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  NULL,
  '{"mode":"text","acceptableAnswers":["papillons, mouches, araignées, chien","papillons, mouches, araignées, hanneton","papillons, mouches, chien, hanneton","papillons, araignées, chien, hanneton","mouches, araignées, chien, hanneton","bêtes, papillons, mouches, araignées","bêtes, papillons, mouches, chien","bêtes, papillons, mouches, hanneton","bêtes, papillons, araignées, chien","bêtes, papillons, araignées, hanneton","bêtes, papillons, chien, hanneton","bêtes, mouches, araignées, chien","bêtes, mouches, araignées, hanneton","bêtes, mouches, chien, hanneton","bêtes, araignées, chien, hanneton"]}'::jsonb,
  'Le champ lexical des animaux comprend dans ce texte : « bêtes », « papillons », « mouches », « araignées », « chien », « hanneton », « bête ». On peut aussi inclure « nids » (habitat animal), « chenil » (habitat du chien), « poil », « babine » (parties du corps animal). Pour le CRPE, il faut relever au moins quatre mots appartenant clairement au champ lexical demandé et justifier le lien thématique.',
  'Inclure des mots qui n''appartiennent pas directement au champ lexical des animaux, comme « cornet » ou « tambour ». Ne retenir que les noms d''animaux proprement dits.',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q15 — lexique — Difficile — qcm — Formation d'un adverbe
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000015',
  'Francais', 'lexique', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Difficile', 'qcm',
  'Comment l''adverbe « violemment » est-il formé ?',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  '[{"id":"a","label":"Adjectif « violent » au féminin + suffixe « -ment » → violentement"},{"id":"b","label":"Adjectif en « -ent » → adverbe en « -emment » (radical « viol- » + « -emment »)"},{"id":"c","label":"Dérivation à partir du verbe « violer » + suffixe « -ment »"},{"id":"d","label":"Emprunt direct au latin « violenter »"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  '« Violemment » est formé à partir de l''adjectif « violent », qui se termine par « -ent ». La règle de formation des adverbes en « -ment » prévoit que les adjectifs en « -ent » forment leur adverbe en « -emment » (et non « -entement ») : violent → violemment, prudent → prudemment, fréquent → fréquemment. De même, les adjectifs en « -ant » donnent des adverbes en « -amment » : brillant → brillamment, savant → savamment. Cette règle orthographique est un classique du CRPE. Attention : « -emment » et « -amment » se prononcent de la même façon [amɑ̃].',
  'Écrire « violentement » en appliquant la règle générale (féminin + « -ment »). Les adjectifs en « -ent » et « -ant » suivent une règle spéciale de formation adverbiale.',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q16 — lexique — Intermediaire — reponse_courte — Préfixe et valeur
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000016',
  'Francais', 'lexique', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Intermediaire', 'reponse_courte',
  'Quel est le préfixe du mot « malpropre » et quelle est sa valeur sémantique ?',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  NULL,
  '{"mode":"text","acceptableAnswers":["mal- (négation)","mal- (négation/défaut)","mal-, négation","mal- négation","préfixe mal-, valeur de négation","mal- : négation","mal-","mal"]}'::jsonb,
  'Le mot « malpropre » est formé du préfixe « mal- » et de l''adjectif « propre ». Le préfixe « mal- » (du latin « male », « de mauvaise manière ») exprime la négation ou le défaut : « malpropre » = « qui n''est pas propre ». Ce préfixe est productif en français : malheureux, maladroit, malveillant, malhonnête. On le distingue du préfixe « in-/im- » (impropre) qui a une valeur similaire mais une origine différente (latin « in- »). L''analyse morphologique des mots par identification des préfixes et suffixes est une compétence fondamentale évaluée au CRPE.',
  'Ne pas identifier « mal- » comme un préfixe et analyser « malpropre » comme un mot simple. « Malpropre » = « mal- » (préfixe de négation) + « propre » (adjectif base).',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q17 — lexique — Difficile — qcm — Figure de style (métaphore)
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000017',
  'Francais', 'lexique', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Difficile', 'qcm',
  'Dans « en cognant contre les parois de sa prison », le mot « prison » désigne le cornet de papier. Quelle figure de style est à l''œuvre ?',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  '[{"id":"a","label":"Une comparaison"},{"id":"b","label":"Une métaphore"},{"id":"c","label":"Une personnification"},{"id":"d","label":"Une hyperbole"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  'Il s''agit d''une métaphore. Le cornet de papier est désigné par le mot « prison » sans outil de comparaison (pas de « comme », « tel que », etc.). La métaphore opère un rapprochement implicite entre le cornet (comparé) et une prison (comparant) : le hanneton est enfermé dans le cornet comme un prisonnier dans sa cellule. Cette métaphore humanise le hanneton et dramatise sa captivité, ce qui reflète la sensibilité de l''enfant. La distinction entre métaphore (sans outil comparatif) et comparaison (avec outil comparatif) est un attendu majeur du CRPE.',
  'Confondre métaphore et comparaison. La comparaison utilise un outil (« comme », « tel que », « semblable à »). Ici, il n''y a pas d''outil : « sa prison » remplace directement « le cornet » → c''est une métaphore.',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q18 — lexique — Difficile — qcm — Valeur de l'adjectif antéposé
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000018',
  'Francais', 'lexique', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Difficile', 'qcm',
  'Dans « Sale enfant ! », quelle est la valeur de l''adjectif « sale » placé avant le nom ?',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  '[{"id":"a","label":"Sens propre : l''enfant est physiquement malpropre"},{"id":"b","label":"Valeur péjorative / injurieuse (sens figuré différent du sens propre postposé)"},{"id":"c","label":"Valeur méliorative : terme d''affection"},{"id":"d","label":"Sens neutre, sans connotation particulière"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  '« Sale » antéposé (avant le nom) a une valeur péjorative et injurieuse, très différente de « sale » postposé (après le nom). Comparez : « un enfant sale » = un enfant physiquement malpropre (sens propre, concret) ; « un sale enfant » = un enfant désagréable, insupportable (sens figuré, péjoratif). Cette différence de sens selon la position de l''adjectif est un phénomène important en français. D''autres adjectifs changent de sens selon leur place : « un grand homme » (illustre) ≠ « un homme grand » (de haute taille) ; « un pauvre homme » (pitoyable) ≠ « un homme pauvre » (sans argent). Ce type d''analyse lexicale est un classique des épreuves du CRPE.',
  'Croire que « sale » a son sens propre (malpropre physiquement). L''antéposition de « sale » lui donne un sens figuré péjoratif. Le contexte confirme : la mère insulte l''enfant, elle ne décrit pas son état physique.',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q19 — lexique — Difficile — qcm — Lien morphologique
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000019',
  'Francais', 'lexique', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Difficile', 'qcm',
  'Quel est le lien morphologique entre les mots « chien » et « chenil » dans le texte ?',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  '[{"id":"a","label":"Ce sont des homonymes sans lien étymologique"},{"id":"b","label":"Ils appartiennent à la même famille (latin « canis »), « chenil » = lieu des chiens (suffixe de lieu « -il »)"},{"id":"c","label":"« Chenil » est un composé savant de « chen- » et « -il » (huile)"},{"id":"d","label":"Ils sont liés par un rapport de synonymie"}]'::jsonb,
  '{"mode":"single_choice","value":"b"}'::jsonb,
  '« Chien » et « chenil » appartiennent à la même famille de mots, issue du latin « canis » (chien). « Chenil » est formé sur la base « chen- » (variante de « chien ») avec le suffixe « -il » qui indique un lieu (comme « fournil » de « four », « terril » de « terre »). Le chenil est donc étymologiquement le « lieu des chiens ». L''identification des familles de mots par leur radical commun et l''analyse des suffixes sont des compétences morphologiques attendues au CRPE. On retrouve la racine latine « canis » dans d''autres mots français : canin, caniche, canicule.',
  'Croire que « chien » et « chenil » n''ont pas de lien morphologique à cause de la différence de forme. La variation « chien/chen- » est une alternance vocalique courante dans les familles de mots d''origine latine.',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;

-- Q20 — lexique — Intermediaire — qcm — Sens mobilisés dans la description
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'd6030000-0000-0000-0000-000000000020',
  'Francais', 'lexique', 'sujet_blanc_crpe_3', 'Sujet blanc n°3 — L''Enfant', 'Intermediaire', 'qcm',
  'Dans la description du chien (« qui sent le chenil, taches fauves, poil hérissé, l''air si bon »), quels sens sont mobilisés ?',
  'Ma mère dit que c''est dégoûtant de montrer qu''on aime les bêtes, et malpropre de jouer avec elles. Mais je n''obéis pas, je cours après les papillons, je m''arrête devant les nids, j''écrase les mouches pour les araignées. C''est ma joie de caresser le chien du voisin ! ce grand chien noir qui sent le chenil, qui a des taches fauves au-dessus des yeux, le poil hérissé sur le dos, un peu de rose à la babine, et l''air si bon ! Ma mère arrive toujours au moment où j''ai le nez dans le poil de la bête ; elle me donne une gifle et me mouche violemment. « Sale enfant ! » crie-t-elle, en me traînant par le bras vers la maison. Le chien a filé. Mais il revient le lendemain, et moi aussi. Je me rappelle aussi un hanneton que j''avais attrapé et que je gardais dans un cornet de papier. Il faisait un bruit de tambour en cognant contre les parois de sa prison. Je l''écoutais, ravi, collant mon oreille contre le cornet ; le bourdonnement me chatouillait et me faisait rire tout seul. Ma mère m''a surpris dans cette joie. — Qu''est-ce que tu as là ? Veux-tu bien jeter cette saleté ! Elle a pris le cornet, l''a ouvert d''un coup sec, et le hanneton s''est envolé, lourd et doré, avec un bruit de toupie. J''ai eu envie de pleurer. Mais je n''ai rien dit, et j''ai serré les poings dans mes poches. — Jules Vallès, L''Enfant (1879), chapitre I',
  '[{"id":"a","label":"Uniquement la vue"},{"id":"b","label":"La vue et l''ouïe"},{"id":"c","label":"La vue, l''odorat et le toucher"},{"id":"d","label":"Les cinq sens"}]'::jsonb,
  '{"mode":"single_choice","value":"c"}'::jsonb,
  'La description du chien mobilise trois sens : 1) L''odorat : « qui sent le chenil » (l''odeur du chien) ; 2) La vue : « taches fauves au-dessus des yeux », « le poil hérissé sur le dos », « un peu de rose à la babine », « ce grand chien noir » (couleurs, formes, aspects visuels) ; 3) Le toucher : « le poil hérissé » (texture), et plus loin « j''ai le nez dans le poil de la bête » (contact physique). L''ouïe et le goût ne sont pas mobilisés dans ce portrait du chien. L''analyse des perceptions sensorielles dans un texte descriptif est une compétence attendue au CRPE pour caractériser les procédés d''écriture.',
  'Oublier l''odorat (« sent le chenil ») ou le toucher (« poil hérissé », contact physique). La description ne se limite pas à la vue : Vallès fait appel à plusieurs sens pour rendre la scène vivante.',
  'valide', 'CRPE Français — Sujet blanc n°3', 'premium', true
) ON CONFLICT (id) DO UPDATE SET instruction = EXCLUDED.instruction, support_text = EXCLUDED.support_text, choices = EXCLUDED.choices, expected_answer = EXCLUDED.expected_answer, detailed_explanation = EXCLUDED.detailed_explanation, common_mistake = EXCLUDED.common_mistake, topic_label = EXCLUDED.topic_label, level = EXCLUDED.level, exercise_type = EXCLUDED.exercise_type, subdomain = EXCLUDED.subdomain, source = EXCLUDED.source;
